const REVIEW_FIXTURES_DIR = resolve(__dirname, '..', 'fixtures', 'review');
const DECISION_FIXTURES_DIR = resolve(__dirname, '..', 'fixtures', 'decisions');

// ---------------------------------------------------------------------------
// Helpers.
// ---------------------------------------------------------------------------

function listFixtureFiles(dir: string, prefix: string): string[] {
  return readdirSync(dir)
    .filter((name) => name.startsWith(prefix) && name.endsWith('.json'))
    .sort();
}

function makeStubLogger(): Logger {
  const noop = vi.fn();
  return {
    info: noop,
    warn: noop,
    error: noop,
    debug: noop,
    trace: noop,
    fatal: noop,
    child: () => makeStubLogger(),
  } as unknown as Logger;
}

function makeDailyDeps(mem: InMemoryDbResult): DailyReviewDeps {
  const repos = {
    cycles: createCyclesRepo(mem.db),
    recoveries: createRecoveryRepo(mem.db),
    sleeps: createSleepsRepo(mem.db),
    workouts: createWorkoutsRepo(mem.db),
    profile: createProfileRepo(mem.db),
    bodyMeasurements: createBodyMeasurementsRepo(mem.db),
    syncRuns: createSyncRunsRepo(mem.db),
    dailySummaries: createDailySummariesRepo(mem.db),
  };
  return {
    repos,
    clock: () => new Date('2026-03-15T15:00:00.000Z'),
    logger: makeStubLogger(),
  };
}

function makeWeeklyDeps(mem: InMemoryDbResult): WeeklyReviewDeps {
  const repos = {
    cycles: createCyclesRepo(mem.db),
    recoveries: createRecoveryRepo(mem.db),
    sleeps: createSleepsRepo(mem.db),
    workouts: createWorkoutsRepo(mem.db),
    profile: createProfileRepo(mem.db),
    bodyMeasurements: createBodyMeasurementsRepo(mem.db),
    syncRuns: createSyncRunsRepo(mem.db),
    decisions: createDecisionsRepo(mem.db),
    dailySummaries: createDailySummariesRepo(mem.db),
  };
  return {
    repos,
    clock: () => new Date('2026-03-15T15:00:00.000Z'),
    ianaZone: () => 'America/Los_Angeles',
    logger: makeStubLogger(),
  };
}

function assertCleanRendered(rendered: string, label: string): void {
  const hit = containsBannedToneToken(rendered);
  const context =
    hit.hit && 'index' in hit ? rendered.slice(Math.max(0, hit.index - 30), hit.index + 30) : '';
  expect(
    hit.hit,
    hit.hit && 'word' in hit
      ? `Banned token '${hit.word}' found in ${label}: ...${context}...`
      : `Banned token found in ${label}`,
  ).toBe(false);
  expect(EMOJI_RE.test(rendered), `Emoji match in ${label}`).toBe(false);
}

// ---------------------------------------------------------------------------
// Sanity (carry forward from Wave 0).
// ---------------------------------------------------------------------------

describe('Phase 4 formatter tone contract — sanity', () => {
  it('BANNED_TONE_WORDS exposes 10 entries (the ADR-0005 canonical list)', () => {
    expect(BANNED_TONE_WORDS).toHaveLength(10);
    expect(BANNED_TONE_WORDS_SET.size).toBe(10);
  });

  it('helpers are importable and shaped correctly', () => {
    expect(typeof containsBannedToneToken).toBe('function');
    expect(EMOJI_RE).toBeInstanceOf(RegExp);
  });
});

// ---------------------------------------------------------------------------
// Catalog source-level lint (ADR-0005 §Enforcement bullet 1).
// ---------------------------------------------------------------------------

describe('catalog source-level lint — ACTION_CATALOG entries', () => {
  for (const entry of ACTION_CATALOG) {
    it(`ACTION_CATALOG[${entry.id}] text passes tone lint`, () => {
      assertCleanRendered(entry.text, `ACTION_CATALOG[${entry.id}]`);
    });
  }
});

describe('catalog source-level lint — DECISION_PROMPT_CATALOG entries', () => {
  for (const entry of DECISION_PROMPT_CATALOG) {
    it(`DECISION_PROMPT_CATALOG[${entry.id}] text passes tone lint`, () => {
      assertCleanRendered(entry.text, `DECISION_PROMPT_CATALOG[${entry.id}]`);
    });
  }
});

describe('catalog source-level lint — API_GAP_ENTRIES entries', () => {
  for (const entry of API_GAP_ENTRIES) {
    it(`API_GAP_ENTRIES[${entry.feature}] all string fields pass tone lint`, () => {
      assertCleanRendered(entry.feature, `API_GAP_ENTRIES[${entry.feature}].feature`);
      assertCleanRendered(
        entry.whoop_consumer_path,
        `API_GAP_ENTRIES[${entry.feature}].whoop_consumer_path`,
      );
      assertCleanRendered(entry.notes, `API_GAP_ENTRIES[${entry.feature}].notes`);
      if (entry.alternative_via_v2 !== null) {
        assertCleanRendered(
          entry.alternative_via_v2,
          `API_GAP_ENTRIES[${entry.feature}].alternative_via_v2`,
        );
      }
    });
  }
});

// ---------------------------------------------------------------------------
// Rendered-output lint — Daily review.
// ---------------------------------------------------------------------------

describe('rendered-output lint — renderDailyReview × every daily fixture', () => {
  const fixtures = listFixtureFiles(REVIEW_FIXTURES_DIR, 'daily-');
  let mem: InMemoryDbResult;
  let deps: DailyReviewDeps;

  beforeEach(() => {
    mem = createInMemoryDb();
    deps = makeDailyDeps(mem);
  });
  afterEach(() => mem.close());

  for (const fixtureFile of fixtures) {
    it(`${fixtureFile} → rendered output free of banned tokens + emoji`, async () => {
      const spec = JSON.parse(
        readFileSync(resolve(REVIEW_FIXTURES_DIR, fixtureFile), 'utf-8'),
      ) as DailyFixtureSpec;
      const expanded = expandDailyFixture(spec);
      deps.repos.cycles.upsertBatch(expanded.cycles);
      deps.repos.recoveries.upsertBatch(expanded.recoveries);
      deps.repos.sleeps.upsertBatch(expanded.sleeps);
      const result = await getDailyReview({ date: spec.reviewed_date }, deps);
      const rendered = renderDailyReview(result);
      assertCleanRendered(rendered, `renderDailyReview(${fixtureFile})`);
    });
  }
});

