// ---------------------------------------------------------------------------
// Rendered-output lint — Decision formatter (3 shapes × 3 fixtures).
// ---------------------------------------------------------------------------

describe('rendered-output lint — renderDecisionList / Detail / Update × every decision fixture', () => {
  const fixtureFiles = listFixtureFiles(DECISION_FIXTURES_DIR, 'decision-');

  for (const fixtureFile of fixtureFiles) {
    it(`${fixtureFile} → list-mode rendered output (when decisions[] available) free of banned tokens`, () => {
      const fx = JSON.parse(readFileSync(resolve(DECISION_FIXTURES_DIR, fixtureFile), 'utf-8')) as {
        decisions?: Decision[];
        decision?: Decision;
        result?: { mode: 'update'; decision: Decision };
      };
      if (fx.decisions !== undefined) {
        const rendered = renderDecisionList(fx.decisions, new Date('2026-03-15T15:00:00.000Z'));
        assertCleanRendered(rendered, `renderDecisionList(${fixtureFile})`);
      }
      if (fx.decision !== undefined) {
        const rendered = renderDecisionDetail(fx.decision);
        assertCleanRendered(rendered, `renderDecisionDetail(${fixtureFile})`);
      }
      if (fx.result !== undefined && fx.result.mode === 'update') {
        const rendered = renderDecisionUpdate(fx.result.decision);
        assertCleanRendered(rendered, `renderDecisionUpdate(${fixtureFile})`);
      }
    });
  }
});

